export class LeaseOption {
	leaseId : number;
	optionType : string;
	optionBeginDate : string;
	optionEndDate : string;
	optionNotificationBeginDate : string;
	optionNotificationEndDate : string;
	optionReminderDate : string;
	optionDescription : string;
	optionDocument : string;
	optionSection : string;
	optionPage : string;
	optionStatus : string;
	optionActionTaken : string;
	optionActionDate : string;
	optionActionNotes : string;
	
	constructor(leaseId, optionType, optionBeginDate, optionEndDate, optionNotificationBeginDate, optionNotificationEndDate, optionReminderDate, optionDescription, optionDocument, optionSection, optionPage, optionStatus, optionActionTaken, optionActionDate, optionActionNotes ) {
		this.leaseId = leaseId;
		this.optionType = optionType;
		this.optionBeginDate = optionBeginDate;
		this.optionEndDate = optionEndDate;
		this.optionNotificationBeginDate = optionNotificationBeginDate;
		this.optionNotificationEndDate = optionNotificationEndDate;
		this.optionReminderDate = optionReminderDate;
		this.optionDescription = optionDescription;
		this.optionDocument = optionDocument;
		this.optionSection = optionSection;
		this.optionPage = optionPage;
		this.optionStatus = optionStatus;
		this.optionActionTaken = optionActionTaken;
		this.optionActionDate = optionActionDate;
		this.optionActionNotes = optionActionNotes;
	}
}

